fn probe(path: &Path) -> Option<Option<PathBuf>> {
    match path.symlink_metadata() {
        Err(_) => None,
        Ok(meta) => {
            if meta.is_symlink() {
                Some(Some(std::fs::read_link(path).unwrap_or_default()))
            } else {
                Some(None)
            }
        }
    }
}

